:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --text-dim: #7f8c8d;
  --border: #ddd;
  --danger: #e74c3c;
  --success: #27ae60;
}

