appsmith.onReady(renderBoundaryDashboard);
appsmith.onModelChange(renderBoundaryDashboard);
function renderBoundaryDashboard() {
  const events = appsmith.model.networkEvents;
  if (!events || !Array.isArray(events)) return;
  const tableBody = document.querySelector('#boundary-body');
  if (!tableBody) return;
  tableBody.innerHTML = "";

  // 1. Data Store for Matching
  const requestMap = new Map();
  const responseMap = new Map();

  // 2. Single Pass to Categorize Events
  events.forEach(event => {
    const {
      method,
      params
    } = event;
    if (!params) return;
    if (method === "Network.requestWillBeSent") {
      requestMap.set(params.requestId, params);
    } else if (method === "Network.responseReceived") {
      responseMap.set(params.requestId, params.response);
    }
  });
  let postCount = 0;
  let tlsActive = false;
  let totalEgressBytes = 0;
  const thirdPartyDomains = new Set();
  const internalDomains = ["academia.edu", "academia-assets.com"];

  // 3. Process Joined Data
  const processedData = [];
  requestMap.forEach((reqTarget, requestId) => {
    const resTarget = responseMap.get(requestId) || {};
    const urlStr = reqTarget.request.url;
    let domain = "unknown";
    try {
      domain = new URL(urlStr).hostname;
    } catch (e) {
      domain = urlStr;
    }
    const method = reqTarget.request.method;
    const protocol = resTarget.securityDetails?.protocol || "TLS 1.3 (Inferred)"; // Many logs show TLS 1.3
    const isThirdParty = !internalDomains.some(d => domain.includes(d));
    const isPost = method === "POST";

    // Stats Calculation
    if (isPost) postCount++;
    if (isThirdParty) thirdPartyDomains.add(domain);
    if (protocol.includes("1.3") || protocol.includes("1.2")) tlsActive = true;

    // 1. Safely access headers
    const headers = reqTarget.request.headers || {};

    // 2. Try to get the header first
    let size = parseInt(headers['Content-Length'] || headers['content-length']) || 0;

    // 3. Fallback: If header is missing, measure the actual POST payload byte size
    if (size === 0 && reqTarget.request.postData) {
      size = new Blob([reqTarget.request.postData]).size;
    }
    totalEgressBytes += size;
    // Risk Logic
    let risk = "LOW";
    if (isPost && isThirdParty) risk = "CRITICAL";else if (isPost) risk = "MEDIUM";else if (isThirdParty) risk = "LOW";
    processedData.push({
      domain,
      method,
      protocol,
      isThirdParty,
      risk,
      isPost
    });
  });

  // 4. Sort: Critical Risks First
  processedData.sort((a, b) => a.risk === "CRITICAL" ? -1 : 1);

  // 5. Render Table
  processedData.forEach(item => {
    const riskColor = item.risk === "CRITICAL" ? "#c0392b" : item.risk === "MEDIUM" ? "#d35400" : "#27ae60";
    const riskBg = item.risk === "CRITICAL" ? "#fce4e4" : item.risk === "MEDIUM" ? "#fcf3cf" : "#e8f8f5";
    const row = document.createElement('tr');
    row.innerHTML = `
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><code>${item.domain}</code></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee; font-weight: bold;">${item.method}</td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><span style="padding: 2px 8px; background: #eee; border-radius: 4px; font-size: 0.8rem;">${item.protocol}</span></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;">${item.isThirdParty ? '🌎 External' : '🏠 Internal'}</td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><span style="padding: 4px 10px; border-radius: 12px; font-size: 0.75rem; font-weight: bold; background: ${riskBg}; color: ${riskColor};">${item.risk}</span></td>
        `;
    tableBody.appendChild(row);
  });

  // 6. Update Counters
  document.getElementById('post-count').textContent = postCount;
  document.getElementById('third-party-count').textContent = thirdPartyDomains.size;
  document.getElementById('tls-status').textContent = tlsActive ? "Verified" : "N/A";
  document.getElementById('egress-volume').textContent = (totalEgressBytes / 1024).toFixed(1) + " KB";

  // Update Header Badge
  const badge = document.getElementById('boundary-status');
  if (postCount > 0) {
    badge.textContent = "Boundary Signal: Active Egress";
    badge.style.background = "#3498db";
  }
}

